package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtBlock;
import spoon.reflect.code.CtConstructorCall;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtStatement;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setComplianceLevel(8);

        // Set the source directory to process
        launcher.addInputResource("/workspace/singer");

        // Process the code
        CtModel model = launcher.buildModel();

        // Find all classes that extend EncoderBase and don't implement the required methods
        model.getElements(new TypeFilter<>(CtClass.class)).forEach(clazz -> {
            // Check if this class extends EncoderBase
            if (clazz.getSuperclass() != null && 
                clazz.getSuperclass().getQualifiedName().contains("EncoderBase")) {

                // Check if it implements the Encoder interface
                boolean implementsEncoder = false;
                for (CtTypeReference<?> iface : clazz.getSuperInterfaces()) {
                    if (iface.getQualifiedName().contains("Encoder")) {
                        implementsEncoder = true;
                        break;
                    }
                }

                if (implementsEncoder) {
                    // Check if it implements footerBytes and headerBytes methods
                    boolean hasFooterBytes = false;
                    boolean hasHeaderBytes = false;

                    for (CtMethod<?> method : clazz.getMethods()) {
                        if (method.getSimpleName().equals("footerBytes")) {
                            hasFooterBytes = true;
                        } else if (method.getSimpleName().equals("headerBytes")) {
                            hasHeaderBytes = true;
                        }
                    }

                    // If missing one or both methods, add them
                    if (!hasFooterBytes || !hasHeaderBytes) {
                        System.out.println("Found EncoderBase subclass missing required methods: " + clazz.getQualifiedName());

                        // Add the missing methods
                        if (!hasFooterBytes) {
                            CtMethod<?> footerMethod = launcher.getFactory().Code().createMethod(
                                "public byte[] footerBytes() { return new byte[0]; }",
                                clazz,
                                clazz.getFactory().Core().createCtTypeReference(byte[].class)
                            );
                            clazz.addMethod(footerMethod);
                        }

                        if (!hasHeaderBytes) {
                            CtMethod<?> headerMethod = launcher.getFactory().Code().createMethod(
                                "public byte[] headerBytes() { return new byte[0]; }",
                                clazz,
                                clazz.getFactory().Core().createCtTypeReference(byte[].class)
                            );
                            clazz.addMethod(headerMethod);
                        }
                    }
                }
            }
        });

        // Write the result back to files
        launcher.setSourceOutputDirectory("/workspace/singer");
        launcher.process();
    }
}

